body:
The clocking block wait @(cb) seems to be released in the Observed region.
I had understood that assertion evaluation occurs after that, but in Verilator, it appears to be happening before the assertion evaluation.

Is my understanding incorrect?

------------------------------------------------------------------------
```
module top();

  // Gen Clock
  localparam PERIOD = 10;

  bit CLK;
  initial
  begin
    #PERIOD;
    forever
    begin
      CLK = ~CLK;
      #(PERIOD/2);
    end
  end

  logic RST_X = 1'b1;

  clocking cb @(posedge CLK);
  endclocking


  logic [3:0] r_cnt;
  always_ff @(posedge CLK, negedge RST_X)
    if(~RST_X)
      r_cnt <= '0;
    else
      r_cnt <= 4'(r_cnt + 1'b1);
  

  initial
  begin
    @(negedge CLK)
      RST_X = 1'b0;
    @(negedge CLK)
      RST_X = 1'b1;

    repeat(20)
      @(posedge CLK);

    $finish;
  end


  chk: assert property
  (
    @(posedge CLK)
    (r_cnt == 4'd5) |-> (1'b0)
  )
    $display("\nasset:  r_cnt=%1d\n", r_cnt);
  else
  begin
    $display("\nnot_asset:  r_cnt=%1d\n", r_cnt );
  end


  initial
  begin
    forever
    begin
      @(cb)
      if(r_cnt == 4'd5)
      begin
        r_cnt = '0;   // This would affect the assertion.
      end
    end
  end

endmodule

```
